// Sanity-Check Prompt-Builder (Code-Knoten VOR chainLlm).
//
// Input: N Items von Szenen-parsen, jedes mit imagePrompt.
// Output: N Items, jedes mit zusätzlichem sanityUserPrompt-Feld.
//
// Wichtig: $input.all().map(...) verarbeitet ALLE Items. Im Default-Mode "Run Once for
// All Items" würde "return [{ json: ... }]" nur 1 Item rausgeben — Bug-Fall.

return $input.all().map(item => {
  const j = item.json || {};
  const imagePrompt = j.imagePrompt || '';
  const sanityUserPrompt = `Review this image prompt for spatial-physics ambiguity. Apply minimal rewriting if needed; preserve everything else verbatim.

--- PROMPT START ---
${imagePrompt}
--- PROMPT END ---`;
  return { json: { ...j, sanityUserPrompt } };
});

// Sanity-Check Parsen (Code-Knoten NACH chainLlm).
//
// Input: N Items vom chainLlm, jedes mit $json.text (JSON-String mit { revisedPrompt, changesMade, issueFound }).
// Wir holen die Original-Items aus 'Sanity-Check Prompt-Builder' per Index.
// Output: N Items, jeweils original-Felder + imagePrompt durch revisedPrompt ersetzt (wenn changesMade=true).

const builderItems = $('Sanity-Check Prompt-Builder').all();
const llmItems = $input.all();

return llmItems.map((llmItem, idx) => {
  const original = builderItems[idx]?.json || llmItem.json || {};
  const originalPrompt = original.imagePrompt || '';

  const llmText = (llmItem.json?.text || '').trim();
  let revised = originalPrompt;
  let changesMade = false;
  let issueFound = null;
  let parseError = null;

  try {
    const m = llmText.match(/\{[\s\S]*\}/);
    if (m) {
      const parsed = JSON.parse(m[0]);
      if (parsed.changesMade === true && typeof parsed.revisedPrompt === 'string' && parsed.revisedPrompt.length > 200) {
        revised = parsed.revisedPrompt;
        changesMade = true;
        issueFound = parsed.issueFound || null;
      }
    } else {
      parseError = 'no JSON object found in LLM output';
    }
  } catch (e) {
    parseError = String(e).substring(0, 200);
  }

  return { json: {
    ...original,
    imagePrompt: revised,
    _sanityCheck: {
      changesMade,
      issueFound,
      parseError,
      originalLength: originalPrompt.length,
      revisedLength: revised.length
    }
  }};
});

