  imagePositions = sceneItems.map(it => ({
    scene: it.json.sceneIndex,
    paragraphIndex: typeof it.json.paragraphIndex === 'number' ? it.json.paragraphIndex : null
  })).filter(p => typeof p.scene === 'number' && uploadedScenes.has(p.scene));
} catch (e) { imagePositions = []; }
data.imagePositions = imagePositions;

let template = $input.item.json.data;

// Sanity: das Sachtext-Template MUSS den Kästen-Platzhalter enthalten. Fehlt er,
// wurde das falsche Template geladen (z.B. demo-template.html) — hart abbrechen.
if (!template.includes('{{SACHTEXT_BLOCKS_JSON}}')) {
  throw new Error('Falsches Template geladen: {{SACHTEXT_BLOCKS_JSON}} fehlt — erwartet wird demo-template-sachtext.html');
}

// Generate image tags — nur fuer real hochgeladene Szenen (echte Szenen-Nummern,
// Luecken wie -1,-2,-4 bleiben korrekt erhalten).
let imagesHtml = '';
for (const i of presentScenes) {
  const imgUrl = `https://rala84.github.io/lesekumpel/bilder/${data.slug}-${i}.png`;
  imagesHtml += `<img src="${imgUrl}" alt="${data.title}" class="hero-image" onerror="this.style.display='none'">\n        `;
}

// SEO-Felder aus der Textlaenge (kein Persona-/Neurotyp-Mapping im Sachtext-Workflow)
const laengenWords = { 'Kurz': '80–150', 'Mittel': '150–250', 'Lang': '250–400' };
const words = data.woerter || laengenWords[data.textlaenge] || '150–250';
const typicalAge = '7–10';
const readingLevelLabel = `${words} Wörter, ${data.personaName || 'Samira Wissensfreund'}`.trim();

const descRaw = `Sachtext für ${typicalAge}-Jährige: ${data.title || ''}. ${data.description || ''}`.trim();
const metaDescription = descRaw.length > 157 ? descRaw.substring(0, 157).trimEnd() + '…' : descRaw;
const metaKeywords = [data.personaName, 'Sachtext', 'Wissen für Kinder', 'Lesetext', 'Lesen lernen', `Kinder ${typicalAge}`]
  .filter(Boolean).join(', ');
const topic = data.description ? data.description.toString().substring(0, 60).trim() : '';
const storyPath = `sachtexte/${data.slug}.html`;
const ogImageUrl = data.personaImg || '';

// HTML-Escape für Attribut-Kontexte (Titel/Beschreibung können Quotes enthalten)
function htmlEscape(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;').replace(/"/g, '&quot;')
    .replace(/</g, '&lt;').replace(/>/g, '&gt;');
}

template = template
  .replace(/\{\{STORY_TITLE\}\}/g, htmlEscape(data.title))
  .replace(/\{\{STORY_DATE\}\}/g, data.date || '')
  .replace(/\{\{PERSONA_NAME\}\}/g, htmlEscape(data.personaName))
  .replace(/\{\{PERSONA_IMG_URL\}\}/g, data.personaImg || '')
  .replace(/\{\{PERSONA_BIO\}\}/g, htmlEscape(data.personaBio))
  .replace(/\{\{NEUROTYP\}\}/g, htmlEscape(data.neurotyp || 'Standard'))
  .replace(/\{\{GENRE\}\}/g, htmlEscape(data.genre))
  .replace(/\{\{STORY_IMAGES_HTML\}\}/g, imagesHtml.trim())
  .replace(/\{\{HERO_IMAGE_URL\}\}/g, `https://rala84.github.io/lesekumpel/bilder/${data.slug}-${presentScenes[0] || 1}.png`)
  .replace(/\{\{RAW_STORY_TEXT\}\}/g, JSON.stringify(data.storyText || ''))
  .replace(/\{\{EMOJI_STORY_TEXT\}\}/g, JSON.stringify(data.emojiStoryText || ''))
  .replace(/\{\{RAW_SUMMARY_TEXT\}\}/g, JSON.stringify(data.summaryText || ''))
  .replace(/\{\{EMOJI_SUMMARY_TEXT\}\}/g, JSON.stringify(data.emojiSummaryText || ''))
  .replace(/\{\{QUIZ_DATA_JSON\}\}/g, JSON.stringify(data.quizData || []))
  .replace(/\{\{WEITERERZAEHLEN_JSON\}\}/g, JSON.stringify(data.weitererzaehlenData || null))
  .replace(/\{\{SCHATZSUCHE_JSON\}\}/g, JSON.stringify(data.schatzsucheData || null))
  .replace(/\{\{DICTIONARY_JSON\}\}/g, JSON.stringify(data.wortschatz || []))
  .replace(/\{\{IMAGE_POSITIONS_JSON\}\}/g, JSON.stringify(data.imagePositions || []))
  .replace(/\{\{SACHTEXT_BLOCKS_JSON\}\}/g, JSON.stringify(data.sachtextBlocks || { wusstestDu: [], checkliste: null }))
  .replace(/\{\{WORD_COUNT\}\}/g, String(data.wordCount || 0))
  .replace(/\{\{IMAGE_MODEL\}\}/g, data.imageModel || '')
  .replace(/\{\{SLUG\}\}/g, data.slug || '')
  .replace(/\{\{RELATED_STORIES_HTML\}\}/g, '')
  // SEO/Meta-Platzhalter
  .replace(/\{\{READING_LEVEL_LABEL\}\}/g, htmlEscape(readingLevelLabel))
  .replace(/\{\{META_DESCRIPTION\}\}/g, htmlEscape(metaDescription))
  .replace(/\{\{META_KEYWORDS\}\}/g, htmlEscape(metaKeywords))
  .replace(/\{\{STORY_PATH\}\}/g, storyPath)
  .replace(/\{\{TOPIC\}\}/g, htmlEscape(topic))
  .replace(/\{\{OG_IMAGE_URL\}\}/g, ogImageUrl)
  .replace(/\{\{PERSONA_AVATAR_URL\}\}/g, ogImageUrl)
  .replace(/\{\{TYPICAL_AGE\}\}/g, htmlEscape(typicalAge));

// Safety-Net: verbliebene Platzhalter loggen und auf '' stripen
const residuals = template.match(/\{\{[A-Z_]+\}\}/g);
if (residuals) {
  const unique = [...new Set(residuals)];
  console.warn('HTML assemblieren (Sachtext): unresolved placeholders ->', unique.join(', '));
  template = template.replace(/\{\{[A-Z_]+\}\}/g, '');
}

const htmlBase64 = Buffer.from(template, 'utf8').toString('base64');
const storyUrl = `https://rala84.github.io/lesekumpel/sachtexte/${data.slug}.html`;

return { json: { ...data, htmlBase64, filePath: `sachtexte/${data.slug}.html`, commitMessage: `Sachtext: ${data.title} — ${data.personaName} (${data.textlaenge || 'Mittel'})`.trim(), storyUrl } };

const prev = $('Story-Elemente vorbereiten').first().json;
const rawText = $input.first().json.text || '';

let storyElements = { characters: [], props: [], setting: '', sceneRules: [] };
try {
  const m = rawText.match(/\{[\s\S]*\}/);
  if (m) storyElements = JSON.parse(m[0]);
} catch(e) {}

if (!Array.isArray(storyElements.sceneRules)) storyElements.sceneRules = [];
if (!Array.isArray(storyElements.characters)) storyElements.characters = [];
if (!Array.isArray(storyElements.props))      storyElements.props      = [];

const clothingRegex = new RegExp("\\b(wearing|shirt|dress|trousers|pants|shorts|jacket|hoodie|coat|sweater|skirt|outfit|clothes|kleidung)\\b", "i");

function clean(s) {
  return (s == null ? '' : String(s)).trim();
}
function has(s) { return clean(s).length > 0 && clean(s).toLowerCase() !== 'null'; }

function indent2(s) {
  return clean(s).split('\n').map(l => '    ' + l).join('\n');
}

function filterVisualOnlyDF(arr) {
  // Filtert Eintraege heraus, die Verhalten/Biologie statt visueller Merkmale beschreiben.
  // Verhaltens-Eintraege ("One eye remains open while sleeping") werden vom Bildmodell
  // visuell umgesetzt und produzieren Uncanny-Valley-Artefakte.
  const BEHAVIOR_RE = /\b(while|when|during|whenever|always|sometimes|remains?|stays?|becomes?|sleeps?|sleeping|asleep|dreams?|dreaming|swims?|swimming|flies|flying|flew|walking|running|jumping|jumps?|dancing|dances?|sings?|singing|breathes?|breathing|breath|observes?|observing|watches?|watching|listens?|listening|hunts?|hunting|hides?|hiding|eats?|eating|drinks?|drinking|rests?|resting|awake|alert|active|asleep|half\s*of\s*its\s*brain|brain\s*rests)\b/i;
  return (arr || []).filter(s => {
    const t = String(s || '').trim();
    if (!t) return false;
    if (BEHAVIOR_RE.test(t)) return false;
    return true;
  });
}

function buildHumanBlock(c, idx) {
  const lines = [];
  const name  = clean(c.name) || ('Character #' + idx);
  const age   = (typeof c.ageYears === 'number' && c.ageYears > 0) ? (c.ageYears + '-year-old ') : '';
  const heightCat = clean(c.body && c.body.heightCategory) || 'child';
  const build     = clean(c.body && c.body.build) || 'average';
  lines.push(`CHARACTER #${idx} — ${name} (${age}${heightCat}):`);
  lines.push(`  BODY:    ${build} ${heightCat} build`);
  if (c.hair) {
    const h = [clean(c.hair.color), clean(c.hair.style), clean(c.hair.length)].filter(has).join(', ');
    if (h) lines.push(`  HAIR:    ${h}`);
  }
  if (c.eyes && has(c.eyes.color)) lines.push(`  EYES:    ${clean(c.eyes.color)}`);
  if (c.skin && has(c.skin.tone))  lines.push(`  SKIN:    ${clean(c.skin.tone)}`);

  // OUTFIT — verbatim slots. Force fallback wenn LLM nichts geliefert hat.
  const o = c.outfit || {};
  let top         = clean(o.top);
  let bottom      = clean(o.bottom);
  let footwear    = clean(o.footwear);
  let accessories = clean(o.accessories) || 'none';
  if (!has(top))      top      = 'plain casual t-shirt in a neutral color';
  if (!has(bottom))   bottom   = 'plain casual trousers';
  if (!has(footwear)) footwear = 'simple closed shoes';
  lines.push(`  OUTFIT (identical in every scene — never alter):`);
  lines.push(`    TOP:         ${top}`);
  lines.push(`    BOTTOM:      ${bottom}`);
  lines.push(`    FOOTWEAR:    ${footwear}`);
  lines.push(`    ACCESSORIES: ${accessories}`);

  const dfArr = filterVisualOnlyDF(Array.isArray(c.distinguishingFeatures) ? c.distinguishingFeatures.filter(has) : []);
  if (dfArr.length > 0) lines.push(`  DISTINGUISHING: ${dfArr.join('; ')}`);
  return lines.join('\n');
}

function buildAnimalBlock(c, idx) {
  const lines = [];
  const name    = clean(c.name) || ('Animal #' + idx);
  const species = clean(c.species) || 'animal';
  lines.push(`CHARACTER #${idx} — ${name} (real ${species}, anatomically accurate animal — NOT a person, NOT a child, NOT in costume, no clothing):`);
  if (c.fur) {
    const f = [clean(c.fur.color), clean(c.fur.pattern)].filter(has).join(', ');
    if (f) lines.push(`  FUR/PLUMAGE: ${f}`);
  }
  if (c.eyes && has(c.eyes.color)) lines.push(`  EYES:        ${clean(c.eyes.color)}`);
  if (c.body && has(c.body.build)) lines.push(`  BODY:        ${clean(c.body.build)}`);
  const dfArr = filterVisualOnlyDF(Array.isArray(c.distinguishingFeatures) ? c.distinguishingFeatures.filter(has) : []);
  if (dfArr.length > 0) lines.push(`  DISTINGUISHING: ${dfArr.join('; ')}`);
  return lines.join('\n');
}

function buildCreatureBlock(c, idx) {
  const lines = [];
  const name    = clean(c.name) || ('Creature #' + idx);
  const species = clean(c.species) || 'fantasy creature';
  lines.push(`CHARACTER #${idx} — ${name} (fantasy ${species}, picture-book creature):`);
  if (c.body) {
    const b = [clean(c.body.heightCategory), clean(c.body.build)].filter(has).join(', ');
    if (b) lines.push(`  BODY:    ${b}`);
  }
  if (c.fur) {
    const f = [clean(c.fur.color), clean(c.fur.pattern)].filter(has).join(', ');
    if (f) lines.push(`  HIDE:    ${f}`);
  }
  if (c.eyes && has(c.eyes.color)) lines.push(`  EYES:    ${clean(c.eyes.color)}`);
  if (c.outfit && (has(c.outfit.top) || has(c.outfit.bottom))) {
    lines.push(`  OUTFIT:`);
    if (has(c.outfit.top))    lines.push(`    TOP:    ${clean(c.outfit.top)}`);
    if (has(c.outfit.bottom)) lines.push(`    BOTTOM: ${clean(c.outfit.bottom)}`);
  }
  const dfArr = filterVisualOnlyDF(Array.isArray(c.distinguishingFeatures) ? c.distinguishingFeatures.filter(has) : []);
  if (dfArr.length > 0) lines.push(`  DISTINGUISHING: ${dfArr.join('; ')}`);
  return lines.join('\n');
}

function buildObjectBlock(c, idx) {
  const name = clean(c.name) || ('Object #' + idx);
  const df   = Array.isArray(c.distinguishingFeatures) ? c.distinguishingFeatures.filter(has) : [];
  const detail = df.length > 0 ? df.join('; ') : 'inanimate object from the story';
  return `CHARACTER #${idx} — ${name} (inanimate object): ${detail}`;
}

function buildCharacterBlock(c, idx) {
  const t = (c && c.type || 'human').toString().toLowerCase();
  if (t === 'animal')   return buildAnimalBlock(c, idx);
  if (t === 'creature') return buildCreatureBlock(c, idx);
  if (t === 'object')   return buildObjectBlock(c, idx);
  return buildHumanBlock(c, idx);
}

function buildPropBlock(p, idx) {
  const lines = [];
  const name = clean(p.name) || ('Prop #' + idx);
  lines.push(`PROP #${idx} — ${name}:`);
  if (has(p.color))    lines.push(`  COLOR:    ${clean(p.color)}`);
  if (has(p.material)) lines.push(`  MATERIAL: ${clean(p.material)}`);
  if (has(p.size))     lines.push(`  SIZE:     ${clean(p.size)}`);
  if (has(p.shape))    lines.push(`  SHAPE:    ${clean(p.shape)}`);
  if (typeof p.count === 'number') lines.push(`  COUNT:    ${p.count}`);
  if (has(p.heldBy))   lines.push(`  HELD BY:  ${clean(p.heldBy)} (${clean(p.heldIn) || 'see story'})`);
  else if (has(p.heldIn) && clean(p.heldIn) !== 'none') lines.push(`  HELD IN:  ${clean(p.heldIn)}`);
  // Prop-Zeitachse: ab welchem Absatz die Prop existiert (>0). Der Szenen-Compiler
  // darf die Prop nur in Szenen ab diesem paragraphIndex zeigen.
  if (typeof p.appearsFromParagraph === 'number' && p.appearsFromParagraph > 0)
    lines.push(`  FIRST APPEARS: from paragraph ${p.appearsFromParagraph} onward`);
  return lines.join('\n');
}

function buildSettingBlock(s) {
  if (!s) return '';
  if (typeof s === 'string') {
    return `SETTING ANCHOR (global atmosphere stays constant; micro-location varies per scene per 'Setting focus'):\n  ${clean(s)}`;
  }
  const lines = ["SETTING ANCHOR (global atmosphere stays constant; micro-location varies per scene per 'Setting focus'):"];
  if (has(s.location))       lines.push(`  LOCATION:        ${clean(s.location)}`);
  if (has(s.timeOfDay))      lines.push(`  TIME-OF-DAY:     ${clean(s.timeOfDay)}`);
  if (has(s.weather))        lines.push(`  WEATHER:         ${clean(s.weather)}`);
  if (has(s.lightDirection)) lines.push(`  LIGHT DIRECTION: ${clean(s.lightDirection)} (consistent shadow direction)`);
  return lines.join('\n');
}

const characterBlocks = storyElements.characters.map((c, i) => buildCharacterBlock(c, i + 1));
const propBlocks      = storyElements.props.map((p, i) => buildPropBlock(p, i + 1));
const settingBlock    = buildSettingBlock(storyElements.setting);

const visualLockSections = [];
if (characterBlocks.length > 0) visualLockSections.push(characterBlocks.join('\n\n'));
if (propBlocks.length > 0)      visualLockSections.push(propBlocks.join('\n\n'));
if (settingBlock)               visualLockSections.push(settingBlock);

const visualLock = visualLockSections.length > 0
  ? '=== VISUAL LOCK (REPEAT VERBATIM IN EVERY SCENE — NEVER ALTER) ===\n\n'
    + visualLockSections.join('\n\n')
    + '\n\n=== END VISUAL LOCK ==='
  : '';

// characterReference bleibt als String erhalten (downstream-Kompat) — jetzt = VISUAL LOCK
const characterReference = visualLock;

const sceneRules = storyElements.sceneRules.filter(r => typeof r === 'string' && r.length > 0);

const hasNonHumanCharacter = (storyElements.characters || []).some(c => {
  const t = (c.type || 'human').toString().toLowerCase();
  return t === 'animal' || t === 'creature';
});

return { json: { ...prev, storyElements, characterReference, visualLock, sceneRules, hasNonHumanCharacter } };

// Knoten: "Emoji parsen" UND "Summary-Emoji parsen" — v2 (2026-06-11)
// Beide Knoten nutzen exakt diesen Code; der EINZIGE Unterschied ist der CFG-Block:
//   Emoji parsen:         { quellKnoten: 'Geschichte parsen', quellFeld: 'rawStoryText', zielFeld: 'emojiStoryText' }
//   Summary-Emoji parsen: { quellKnoten: 'Emoji parsen',      quellFeld: 'summaryText',  zielFeld: 'emojiSummaryText' }
// Bei Änderungen: Code unterhalb des CFG-Blocks in BEIDEN Knoten identisch halten.
const CFG = { quellKnoten: 'Geschichte parsen', quellFeld: 'rawStoryText', zielFeld: 'emojiStoryText' };

const origData = $(CFG.quellKnoten).first().json;
const taggerOutput = $input.item.json.text || '[]';
const rawText = origData[CFG.quellFeld] || '';

// Parse Emoji-Annotations
let annotations = [];
try {
  const m = taggerOutput.match(/\[[\s\S]*\]/);
  if (m) annotations = JSON.parse(m[0]);
} catch(e) {
  console.warn('EMOJI-PARSE: JSON parse error:', e.message);
  console.warn('EMOJI-PARSE: Tagger output was:', taggerOutput.substring(0, 500));
}

// Fallback: rule-based emoji insertion if LLM returned nothing
if (!Array.isArray(annotations) || annotations.length === 0) {
  const fallbackMap = [
    { wort: 'froh', emoji: '😊' }, { wort: 'fröhlich', emoji: '😊' },
    { wort: 'glücklich', emoji: '😊' }, { wort: 'freut', emoji: '😊' },
    { wort: 'lacht', emoji: '😊' }, { wort: 'lachte', emoji: '😊' },
    { wort: 'traurig', emoji: '😢' }, { wort: 'weint', emoji: '😢' },
    { wort: 'weinte', emoji: '😢' }, { wort: 'vermisst', emoji: '😢' },
    { wort: 'enttäuscht', emoji: '😢' },
    { wort: 'wütend', emoji: '😠' }, { wort: 'sauer', emoji: '😠' },
    { wort: 'ärgert', emoji: '😠' },
    { wort: 'Angst', emoji: '😨' }, { wort: 'erschrocken', emoji: '😨' },
    { wort: 'ängstlich', emoji: '😨' }, { wort: 'fürchtet', emoji: '😨' },
    { wort: 'überrascht', emoji: '😮' }, { wort: 'erstaunt', emoji: '😮' },
    { wort: 'nervös', emoji: '😰' }, { wort: 'unsicher', emoji: '😰' },
    { wort: 'aufgeregt', emoji: '😰' },
    { wort: 'mutig', emoji: '💪' }, { wort: 'traut', emoji: '💪' },
    { wort: 'frustriert', emoji: '😤' }, { wort: 'genervt', emoji: '😤' },
    { wort: 'erleichtert', emoji: '😌' }, { wort: 'beruhigt', emoji: '😌' },
    { wort: 'stolz', emoji: '😏' }, { wort: 'zufrieden', emoji: '😏' },
    { wort: 'liebt', emoji: '🥰' }, { wort: 'mag', emoji: '🥰' },
  ];
  const lowerText = rawText.toLowerCase();
  for (const entry of fallbackMap) {
    if (lowerText.includes(entry.wort.toLowerCase())) {
      annotations.push(entry);
    }
  }
  if (annotations.length > 0) {
    console.log('EMOJI-PARSE: Used rule-based fallback, found ' + annotations.length + ' emotion words');
  }
}

// Insert emojis into original text (deterministic, no LLM rewriting)
let emojiText = rawText;
if (Array.isArray(annotations) && annotations.length > 0) {
  // Sort by position in text (last first to preserve indices)
  const positions = [];
  for (const a of annotations) {
    if (!a.wort || !a.emoji) continue;
    // Find all occurrences of this word in the text
    let searchFrom = 0;
    while (true) {
      const idx = emojiText.indexOf(a.wort, searchFrom);
      if (idx === -1) break;
      // Check if emoji already inserted after this word
      const afterWord = idx + a.wort.length;
      if (emojiText[afterWord] !== ' ' || !isEmoji(emojiText[afterWord + 1])) {
        positions.push({ idx: afterWord, emoji: a.emoji, wort: a.wort });
      }
      searchFrom = idx + a.wort.length + 1;
      break; // Only first occurrence per annotation
    }
  }

  // Sort descending so we insert from end to start (preserves indices)
  positions.sort((a, b) => b.idx - a.idx);

  for (const p of positions) {
    emojiText = emojiText.substring(0, p.idx) + ' ' + p.emoji + emojiText.substring(p.idx);
  }
}

function isEmoji(char) {
  if (!char) return false;
  const cp = char.codePointAt(0);
  return cp > 0x1F000;
}

// Apply Silbentrennung to emoji text
function silbentrennung(wort) {
  if (wort.length <= 3) return wort;
  if (!/^[a-zäöüß]+$/i.test(wort)) return wort;
  const w = wort.toLowerCase();
  const einheiten = [];
  let i = 0;
  while (i < w.length) {
    if (i+2 < w.length && w.substring(i, i+3) === 'sch') { einheiten.push({text:w.substring(i,i+3),typ:'K',pos:i,len:3}); i+=3; continue; }
    const zwei = i+1<w.length ? w.substring(i,i+2) : '';
    if (['ch','ck','ph','th','qu','pf'].includes(zwei)) { einheiten.push({text:zwei,typ:'K',pos:i,len:2}); i+=2; continue; }
    if (['ei','au','eu','äu','ie','ai'].includes(zwei)) { einheiten.push({text:zwei,typ:'V',pos:i,len:2}); i+=2; continue; }
    const vokal = 'aeiouyäöü'.includes(w[i]);
    einheiten.push({text:w[i],typ:vokal?'V':'K',pos:i,len:1}); i++;
  }
  const vokalIndices = [];
  for (let e=0; e<einheiten.length; e++) {
    if (einheiten[e].typ==='V') {
      if (vokalIndices.length>0 && vokalIndices[vokalIndices.length-1].end===e) vokalIndices[vokalIndices.length-1].end=e+1;
      else vokalIndices.push({start:e,end:e+1});
    }
  }
  if (vokalIndices.length<2) return wort;
  const trennstellen = [];
  for (let v=0; v<vokalIndices.length-1; v++) {
    const nachVokal = vokalIndices[v].end;
    const vorVokal = vokalIndices[v+1].start;
    const anzahlKons = vorVokal - nachVokal;
    let trennEinheit;
    if (anzahlKons===0) trennEinheit=nachVokal;
    else if (anzahlKons===1) trennEinheit=nachVokal;
    else { trennEinheit=vorVokal-1;
      if (anzahlKons>=2) { const vl=einheiten[vorVokal-2]; const lt=einheiten[vorVokal-1];
        if (vl.text==='s'&&lt.text==='t') trennEinheit=vorVokal-2;
      }
    }
    const charPos = einheiten[trennEinheit].pos;
    if (charPos>0 && charPos<wort.length) trennstellen.push(charPos);
  }
  if (!trennstellen.length) return wort;
  let erg='', letzte=0;
  for (const pos of trennstellen) { erg+=wort.substring(letzte,pos)+'-'; letzte=pos; }
  return erg+wort.substring(letzte);
}

const ergebnis = emojiText.replace(/[a-zäöüßA-ZÄÖÜ]{4,}/g, (w) => silbentrennung(w));

return { json: { ...origData, [CFG.zielFeld]: ergebnis } };

